	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Generate and write HTML response
	htmlContent := generateSearchResultsPage(escapedKeyword)
	fmt.Fprint(w, htmlContent)
}

// generateSearchResultsPage generates the HTML content for search results page
func generateSearchResultsPage(keyword string) string {
	html := `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Search Results - Product Search</title>
