// Analytics represents search analytics data
type Analytics struct {
	Keyword   string    `json:"keyword"`
	Timestamp time.Time `json:"timestamp"`
	UserAgent string    `json:"user_agent"`
}

// HandleProductSearch handles product search requests with analytics
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Get the keyword from query parameters
	keyword := r.URL.Query().Get("keyword")

	// If no keyword provided, show an empty search results page
	if keyword == "" {
		keyword = ""
	}

	// Escape HTML to prevent XSS attacks
	escapedKeyword := html.EscapeString(keyword)

	// Log analytics data
	analytics := Analytics{
		Keyword:   keyword,
		Timestamp: time.Now(),
		UserAgent: r.Header.Get("User-Agent"),
	}
	logAnalytics(analytics)

	// Set response content type to HTML
