</head>
<body>
    <div class="container">
        <h2>Search Results: %s</h2>
        <div class="search-info">
            <p>Showing results for: <strong>%s</strong></p>
        </div>
        <div class="results-container">
            %s
        </div>
    </div>
</body>
</html>`, escapedKeyword, escapedKeyword, escapedKeyword, getResultsContent(keyword))

	// Write response
	fmt.Fprint(w, htmlResponse)
}

// getResultsContent returns the appropriate content based on search keyword
func getResultsContent(keyword string) string {
	if keyword == "" {
		return `<div class="no-results">
            <p>Please enter a search keyword to find products.</p>
        </div>`
	}

	return fmt.Sprintf(`<div class="no-results">
        <p>No products found matching "%s".</p>
        <p>Try adjusting your search terms or browse our categories.</p>
    </div>`, html.EscapeString(keyword))
}

// logAnalytics logs search analytics data
func logAnalytics(analytics Analytics) {
	log.Printf("[ANALYTICS] Keyword: %s | Timestamp: %s | UserAgent: %s",
		analytics.Keyword,
		analytics.Timestamp.Format(time.RFC3339),
		analytics.UserAgent,
	)
}

func main() {
	// Register the search handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server
	port := ":8080"
	log.Printf("Server starting on http://localhost%s", port)
	log.Printf("Try: http://localhost%s/search?keyword=laptop", port)

	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatalf("Server error: %v", err)
	}
}

