package main

import (
	"fmt"
	"html"
	"net/http"
	"strings"
)

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Get the keyword query parameter
	keyword := r.URL.Query().Get("keyword")

	// Escape the keyword to prevent XSS attacks
	escapedKeyword := html.EscapeString(keyword)

	// Build the HTML response
	htmlContent := buildSearchResultsHTML(escapedKeyword)

	// Write the response
	fmt.Fprint(w, htmlContent)
}

func buildSearchResultsHTML(keyword string) string {
	var sb strings.Builder

	sb.WriteString("<!DOCTYPE html>\n")
	sb.WriteString("<html>\n")
	sb.WriteString("<head>\n")
	sb.WriteString("    <meta charset=\"UTF-8\">\n")
	sb.WriteString("    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n")
	sb.WriteString("    <title>Search Results</title>\n")
	sb.WriteString("    <style>\n")
	sb.WriteString("        body { font-family: Arial, sans-serif; margin: 20px; }\n")
	sb.WriteString("        h2 { color: #333; }\n")
	sb.WriteString("        .no-results { color: #666; font-style: italic; }\n")
	sb.WriteString("    </style>\n")
	sb.WriteString("</head>\n")
	sb.WriteString("<body>\n")

	// Add the search results heading with the keyword
	if keyword != "" {
		sb.WriteString(fmt.Sprintf("    <h2>Search Results: %s</h2>\n", keyword))
	} else {
		sb.WriteString("    <h2>Search Results: </h2>\n")
		sb.WriteString("    <p class=\"no-results\">Please enter a keyword to search.</p>\n")
	}

	sb.WriteString("</body>\n")
	sb.WriteString("</html>\n")

	return sb.String()
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	serverAddr := ":8080"
	fmt.Printf("Server started on http://localhost%s\n", serverAddr)
	fmt.Println("Try accessing: http://localhost:8080/search?keyword=laptop")

	if err := http.ListenAndServe(serverAddr, nil); err != nil {
		fmt.Printf("Server error: %v\n", err)
	}
}

