	keyword := r.URL.Query().Get("keyword")

	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Create a template with proper escaping
	tmpl, err := template.New("search").Parse(`<!DOCTYPE html>
<html>
<head>
<title>Product Search Results</title>
</head>
<body>
<h2>Search Results: {{.}}</h2>
</body>
</html>`)

	if err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}

	// Execute the template with the keyword (automatically escaped)
	err = tmpl.Execute(w, template.HTML(template.HTMLEscapeString(keyword)))
	if err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}
}

